/// Look up the Indic_Conjunct_Break property for a codepoint.
///
/// Returns `InCB::None` for codepoints without an assigned InCB class.
#[inline]
pub(crate) fn incb_class(c: char) -> InCB {
    let cp = c as u32;
    match INCB_RANGES.binary_search_by(|&(start, end, _)| {
        if cp < start {
            core::cmp::Ordering::Greater
        } else if cp > end {
            core::cmp::Ordering::Less
        } else {
            core::cmp::Ordering::Equal
        }
    }) {
        Ok(idx) => match INCB_RANGES[idx].2 {
            1 => InCB::Extend,
            2 => InCB::Linker,
            3 => InCB::Consonant,
            _ => InCB::None,
        },
        Err(_) => InCB::None,
    }
}
